const messages = $.steps.fetchEmails.response.messages || [];
const ids = messages.map(m => m.id).filter(Boolean).slice(0, 20);
let emailData = 'Found ' + ids.length + ' emails matching query.\n\n';
ids.forEach((id, i) => {
  emailData += (i + 1) + '. Message ID: ' + id + '\n';
});
return { emailData, emailCount: ids.length, messageIds: ids };

const d = $.steps.extractEmails.output;
const today = new Date().toISOString().slice(0, 10);
const dayName = new Date().toLocaleDateString('en-US', { weekday: 'long' });

let prompt = 'You are an AI-powered email and calendar management assistant. Analyze the inbox data and provide comprehensive management recommendations.\n\n';
prompt += 'DATE: ' + dayName + ', ' + today + '\n';
prompt += 'INBOX DATA:\n' + d.emailData + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Classify emails into: urgent-action, needs-reply, informational, promotional, can-archive\n';
prompt += '- Suggest draft reply topics for emails needing responses\n';
prompt += '- Identify any meeting-related emails and suggest calendar actions\n';
prompt += '- Create a prioritized action list for the day\n';
prompt += '- Suggest optimal time blocks for email processing\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "reportDate": "' + today + '",\n';
prompt += '  "totalProcessed": ' + d.emailCount + ',\n';
prompt += '  "classification": {\n';
prompt += '    "urgentAction": { "count": 0, "description": "emails needing immediate action" },\n';
prompt += '    "needsReply": { "count": 0, "suggestedReplies": ["brief reply topic"] },\n';
prompt += '    "informational": { "count": 0, "description": "FYI emails" },\n';
prompt += '    "promotional": { "count": 0, "description": "marketing/promo" },\n';
prompt += '    "canArchive": { "count": 0, "description": "safe to archive" }\n';
prompt += '  },\n';
prompt += '  "calendarSuggestions": [{ "action": "schedule|reschedule|block", "description": "what to do", "suggestedTime": "when" }],\n';
prompt += '  "dailyPlan": [{ "timeBlock": "9:00-9:30", "task": "what to do", "priority": "high|medium|low" }],\n';
prompt += '  "executiveSummary": "2-3 sentence inbox overview",\n';
prompt += '  "topActions": ["action item 1", "action item 2", "action item 3"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { reportDate: new Date().toISOString().slice(0, 10), totalProcessed: 0, classification: {}, calendarSuggestions: [], dailyPlan: [], executiveSummary: raw, topActions: [] }; }

const ai = $.steps.parseAI.output;
const rows = [];
rows.push(['Date', 'Category', 'Count', 'Description', 'Top Actions']);
const cls = ai.classification || {};
Object.keys(cls).forEach(cat => {
  const c = cls[cat];
  rows.push([ai.reportDate || '', cat, String(c.count || 0), c.description || '', (c.suggestedReplies || []).join('; ')]);
});
rows.push([ai.reportDate || '', 'SUMMARY', String(ai.totalProcessed || 0), ai.executiveSummary || '', (ai.topActions || []).join('; ')]);
return { rows };

const ai = $.steps.parseAI.output;
const cls = ai.classification || {};

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email & Calendar Daily Brief', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Date:* ' + (ai.reportDate || 'Today') + ' | *Emails Processed:* ' + (ai.totalProcessed || 0) } });
blocks.push({ type: 'divider' });

if (ai.executiveSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + ai.executiveSummary.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

let classText = '*Inbox Classification:*\n';
if (cls.urgentAction) classText += ':red_circle: *Urgent:* ' + cls.urgentAction.count + ' - ' + (cls.urgentAction.description || '') + '\n';
if (cls.needsReply) classText += ':large_yellow_circle: *Needs Reply:* ' + cls.needsReply.count + '\n';
if (cls.informational) classText += ':large_blue_circle: *Informational:* ' + cls.informational.count + '\n';
if (cls.promotional) classText += ':white_circle: *Promotional:* ' + cls.promotional.count + '\n';
if (cls.canArchive) classText += ':wastebasket: *Archive:* ' + cls.canArchive.count + '\n';
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: classText.slice(0, 1800) } });

if (ai.topActions && ai.topActions.length > 0) {
  blocks.push({ type: 'divider' });
  let actText = '*Top Actions:*\n';
  ai.topActions.forEach((a, i) => { actText += (i + 1) + '. ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: actText.slice(0, 1800) } });
}

if (ai.dailyPlan && ai.dailyPlan.length > 0) {
  blocks.push({ type: 'divider' });
  let planText = '*Suggested Daily Plan:*\n';
  ai.dailyPlan.slice(0, 6).forEach(p => {
    const icon = p.priority === 'high' ? ':red_circle:' : p.priority === 'low' ? ':white_circle:' : ':large_blue_circle:';
    planText += icon + ' *' + p.timeBlock + '* - ' + p.task + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: planText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Report saved to Google Sheets | Powered by Gmail + Claude AI' }] });
const fallback = 'Email Brief: ' + (ai.executiveSummary || '').slice(0, 100);
return { blocks, fallback };
